import{_ as e,c as i,o as t,ag as s}from"./chunks/framework.CgegSSb6.js";const u=JSON.parse('{"title":"Running the GUI","description":"","frontmatter":{},"headers":[],"relativePath":"articles/running-the-gui.md","filePath":"articles/running-the-gui.md"}'),n={name:"articles/running-the-gui.md"};function l(o,a,r,h,c,d){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="running-the-gui" tabindex="-1">Running the GUI <a class="header-anchor" href="#running-the-gui" aria-label="Permalink to &quot;Running the GUI&quot;">​</a></h1><p>This guide covers how to launch Robocode Tank Royale after installation and how to use the portable JAR distribution.</p><h2 id="after-native-installation" tabindex="-1">After native installation <a class="header-anchor" href="#after-native-installation" aria-label="Permalink to &quot;After native installation&quot;">​</a></h2><p>If you installed the native package, the GUI should be available from your operating system&#39;s application menu or launcher as <strong>Robocode Tank Royale GUI</strong>.</p><p>If the application fails to start, verify that:</p><ul><li>Java 11 or newer is installed</li><li><code>JAVA_HOME</code> points to your Java installation</li><li><code>java -version</code> works from a terminal</li></ul><h2 id="running-the-portable-jar" tabindex="-1">Running the portable JAR <a class="header-anchor" href="#running-the-portable-jar" aria-label="Permalink to &quot;Running the portable JAR&quot;">​</a></h2><p>If you prefer a portable installation, download the standalone JAR from the <a href="https://github.com/robocode-dev/tank-royale/releases" target="_blank" rel="noreferrer">GitHub Releases</a>.</p><p>The file name is <code>robocode-tankroyale-gui-x.y.z.jar</code>, where <code>x.y.z</code> is the release version.</p><p>You might be able to launch the JAR directly by double-clicking it. If that does not work, run it from a terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robocode-tankroyale-gui-x.y.z.jar</span></span></code></pre></div><h2 id="using-a-dedicated-directory" tabindex="-1">Using a dedicated directory <a class="header-anchor" href="#using-a-dedicated-directory" aria-label="Permalink to &quot;Using a dedicated directory&quot;">​</a></h2><p>It is often useful to place the JAR in a dedicated directory such as <code>C:\\Robocode</code> or <code>~/Robocode</code>.</p><p>Why:</p><ul><li>it keeps Robocode files together</li><li>it makes launcher scripts easier to manage</li><li>it gives you a predictable place for optional resources such as <code>sounds/</code></li></ul><h3 id="example-launcher-script-on-windows" tabindex="-1">Example launcher script on Windows <a class="header-anchor" href="#example-launcher-script-on-windows" aria-label="Permalink to &quot;Example launcher script on Windows&quot;">​</a></h3><div class="language-batch vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">batch</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@echo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> off</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">java -jar robocode-tankroyale-gui-x.y.z.jar</span></span></code></pre></div><h3 id="example-launcher-script-on-linux-or-macos" tabindex="-1">Example launcher script on Linux or macOS <a class="header-anchor" href="#example-launcher-script-on-linux-or-macos" aria-label="Permalink to &quot;Example launcher script on Linux or macOS&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robocode-tankroyale-gui-x.y.z.jar</span></span></code></pre></div><p>Make the script executable on Linux or macOS:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run-robocode.sh</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="./installing-sample-bots.html">Installing sample bots</a></li><li><a href="./installing-sounds.html">Installing sounds</a></li><li><a href="./gui.html">The GUI</a></li></ul>`,23)])])}const g=e(n,[["render",l]]);export{u as __pageData,g as default};
